<?php declare(strict_types=1);namespace Tests;use PDO;use PHPUnit\Framework\TestCase;use SecretariaApi\Repositories\SecretariaRepository;use SecretariaApi\Services\SecretariaService;
final class SecretariaServiceTest extends TestCase{private SecretariaService$s;protected function setUp():void{$db=new PDO('sqlite::memory:');$db->setAttribute(PDO::ATTR_DEFAULT_FETCH_MODE,PDO::FETCH_ASSOC);$db->exec('CREATE TABLE turmas(id INTEGER PRIMARY KEY,nome_turma TEXT,ano_letivo INTEGER);CREATE TABLE alunos(id INTEGER PRIMARY KEY,nome_completo TEXT,data_nascimento TEXT,id_turma INTEGER,telefone_aluno TEXT,telefone_responsavel TEXT);');$db->exec("INSERT INTO turmas VALUES(1,'7º A',2026);INSERT INTO alunos VALUES(1,'Ana','2013-01-02',1,'111','222')");$this->s=new SecretariaService(new SecretariaRepository($db));}public function testListaFiltraAno():void{[$rows,$meta]=$this->s->turmas(['ano_letivo'=>2026]);self::assertCount(1,$rows);self::assertSame(1,$meta['total']);}public function testTelefonesNuncaSaoRetornados():void{$a=$this->s->aluno(1);self::assertArrayNotHasKey('telefone_aluno',$a);self::assertArrayNotHasKey('telefone_responsavel',$a);}public function testAlunosDaTurma():void{[$rows]=$this->s->alunos(1,[]);self::assertSame('Ana',$rows[0]['nome_completo']);}}
